prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelId ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(CONTAINS(LCASE(STR(?origId)), "1cd93309017949fdbebf0f7d7ea50b4a") || CONTAINS(LCASE(STR(?normId)), "1cd93309017949fdbebf0f7d7ea50b4a"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?msgFlow ?msgFlowName ?sourceRef ?targetRef ?messageRef WHERE {
  ?msgFlow a bboExt:MessageFlow .
  OPTIONAL { ?msgFlow bbo:name ?msgFlowName . }
  OPTIONAL { ?msgFlow bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?msgFlow bboExt:targetRef ?targetRef . }
  OPTIONAL { ?msgFlow bboExt:messageRef ?messageRef . }

  ?endEvent bbo:name "Car is returned" .
  ?endEvent tai:belongsTo* ?model .
  ?model tai:originalId "1cd93309017949fdbebf0f7d7ea50b4a" .

  FILTER(CONTAINS(STR(?endEvent), ?sourceRef) || CONTAINS(STR(?endEvent), ?targetRef))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?msgFlow ?msgFlowName ?sourceRef ?targetRef ?messageRef ?msgName WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo bbo:name "qualityInspection" .

  ?msgFlow a bboExt:MessageFlow .
  ?msgFlow tai:belongsTo ?choreo .
  OPTIONAL { ?msgFlow bbo:name ?msgFlowName . }
  OPTIONAL { ?msgFlow bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?msgFlow bboExt:targetRef ?targetRef . }
  OPTIONAL { ?msgFlow bboExt:messageRef ?messageRef . }

  OPTIONAL {
    ?msg a bboExt:Message .
    ?msg tai:belongsTo ?choreo .
    FILTER(STRENDS(STR(?msg), ?messageRef))
    OPTIONAL { ?msg bbo:name ?msgName . }
  }
}
LIMIT 50

